var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"신의의 선별이 시작된 지 하루가 지났습니다만.","JPN":"神衣の選抜が始まって1日が過ぎましたが。","ENG":"It's been more than a day since they started judging the contestants.","TWN":"聖衣選拔開始後經過一天，"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"현재 참가 인원의 대부분이 포기 의사를 밝힌 상태입니다.","JPN":"現在、参加者のほとんどが諦めた状態です。","ENG":"Most of the participants have conceded already.","TWN":"目前大多數參賽者都表達出棄選的意願。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"구원자도 구원자지만, 성녀와 대면하기 위해 참가한 경우도 허다한 것 같습니다.","JPN":"救世主も救世主ですが、聖女を一目見ようと参加した者も多数いたと思われます。","ENG":"The Savior aside, it seems a lot of them participated to meet the Saintess as well.","TWN":"雖然大部分的人都是為救贖者大人而來，但也有一部分是為聖女而來的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"민중은 거짓된 성녀의 이미지에 현혹되었으며 뜻하지 않게 평민이 움직였다라.","JPN":"民衆は偽りの聖女のイメージに惑わされ、意図とは異なり平民は動き、か。","ENG":"The people were deceived by the false image of the Saintess, and the peasant stepped in unexpectedly.","TWN":"民眾是被虛假的聖女形象所迷惑，沒想到連平民也忍不住出手。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"초운은 버림받았으나 인복만큼은 타고난 건가?","JPN":"地格には見放されたが、人徳だけは恵まれたとでもいうのか？","ENG":"Fortune has forsaken her at birth, but she must be fortunate enough to have generous people around her.","TWN":"雖然命不好，卻受到人的眷顧呢？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"정말이지. 기대했던 것보다 무료한 공연이로군.","JPN":"まったく。期待外れの公演だな。","ENG":"How dull of a show.","TWN":"真是的，原來還很期待的，結果是齣無聊的戲。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"죄송합니다, 전하. 그래도 제가 한 건 조금 격려해준 게 전부예요.","JPN":"すみません、殿下。でも、僕のしたことといっても、少し励ましてあげた程度ですから。","ENG":"I apologize, Your Highness. But all I did was to give her a little encouragement.","TWN":"抱歉，殿下。不過我只是稍微鼓勵她一下而已。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"제가 말을 걸지 않았더라도 결과는 같았을 거라 생각합니다.","JPN":"僕が話しかけなかったとしても、結果は同じだったと思います。","ENG":"I think the outcome would've been the same even if I hadn't talked to her.","TWN":"就算我不說話，結果也會是一樣的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"성설한 여인을 선별하는 자리에서 제국의 성녀가 진다니 어불성설이지.","JPN":"清らかな女性を選抜する場で、帝国の聖女が負けるなどあり得ない。","ENG":"It would be absurd for the Saintess of the Empire to lose in a competition to elect a sacred woman.","TWN":"在選拔聖潔女性的場合，帝國的聖女落敗的話豈不荒謬？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"내가 말하는 건 결과가 아닌 과정이다.","JPN":"私が話しているのは、結果ではなく過程のことだ。","ENG":"What mattered was the process, not the outcome.","TWN":"我指的是過程，不是結果。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"정찰까지 제외해줬건만 부전승이라니. 모처럼의 축제인데 아쉬울 따름이야.","JPN":"偵察の役まで外してやったのに不戦勝とは。せっかくの祭りなのに残念で仕方ない。","ENG":"I even let her skip her scouting duties, and she won by default. It was supposed to be festive, but what a shame.","TWN":"竟然就這樣不戰而勝，難得的慶典，真是可惜。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"저, 전하!","JPN":"で、殿下！","ENG":"Y-Your Highness!","TWN":"殿，殿下！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"대장님? 몸이 다 낫지 않으셨을 텐데, 벌써부터 그렇게 움직여도 괜찮은 건가요?","JPN":"隊長？　まだ怪我が治ってないはずなのに、そんなに動いて大丈夫なんですか？","ENG":"Captain? You couldn't have fully recovered yet. Should you be moving already?","TWN":"隊長？你的傷還沒痊癒吧，這樣跑出來沒關係嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"표정이 안 좋아 보이는군. 무슨 일이지?","JPN":"顔色が悪いな。どうした。","ENG":"You look concerned. What is it?","TWN":"你的臉色看起來不太好，發生什麼事？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"기존에 파악됐던 괴수가 전부가 아니었습니다. 땅굴 속에 놈들이 숨어 있었어요!","JPN":"こちらで把握していた怪獣がすべてではありませんでした。奴ら、穴を堀って隠れていたんです！","ENG":"There are more monsters than we previously estimated. There were more hiding in an underground tunnel!","TWN":"先前所確認到的怪獸並非全部，還有其他的怪獸藏在地洞裡！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L23_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"규모도, 진격 속도도 심상치 않습니다.","JPN":"規模も、進撃のスピードも尋常ではありません。","ENG":"A sizable horde is approaching us at an alarming speed.","TWN":"規模和進攻速度都不尋常。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"이대로 가면 마을까지 다다르는 건 시간문제입니다!","JPN":"このままだと、村にたどり着くのは時間の問題です！","ENG":"It's a matter of time before they reach the village.","TWN":"照這樣下去，到達村莊只是時間問題！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"쯧. 연회에 초대받지 않은 손님이 온 모양이군.","JPN":"チッ。宴に招かれざる客の到来か。","ENG":"Tsk. It seems we have some unwanted guests.","TWN":"啧，這些不速之客。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"평민. 서둘러 병사들을 모아라! 놈들보다 빠르게…","JPN":"平民。急いで兵士を集めろ！　奴らより早く……","ENG":"Peasant, make haste and gather the soldiers! We have to–","TWN":"平民，迅速召集士兵！要比它們更快…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이건…? 비행형? 육안을 피해 여기까지 온 건가!","JPN":"これは……？　飛行型？　人目を避けてここまで来たというのか！","ENG":"What...? A flying monster? How did it make it all the way here without getting noticed?!","TWN":"這是…？飛行型？它們避開耳目到這裡來的嗎！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"샬롯!","JPN":"シャーロット！","ENG":"Carlota!","TWN":"夏洛特！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"죄송합니다, 전하. 몇 마리를 놓쳤습니다.","JPN":"申し訳ございません、殿下。何匹か逃してしまいました。","ENG":"Forgive me, Your Highness. I let a few get away.","TWN":"抱歉，殿下。失手錯放幾隻。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L37_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"추격할까요?","JPN":"追いかけますか？","ENG":"Should I go after them?","TWN":"要追嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"하지만 괴수 군집이 다가오는 중이야. 우리가 물러난다면 마을 사람들이 위험해.","JPN":"でも、怪獣の群れが近づいて来てる。僕たちが退けば村の人たちが危ない。","ENG":"But the horde of monsters is approaching. The villagers will be in danger if we leave.","TWN":"但怪獸正在逼近，如果我們撤退，村民會有危險。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"전하. 저번처럼 병력을 나누는 건 어떨까요?","JPN":"殿下。この前みたいに、兵力を分けるのはどうですか？","ENG":"How about we divide our forces like last time, Your Highness?","TWN":"殿下，像上次那樣分配兵力如何？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"그러기엔 부상자들이 많습니다. 당장 괴수를 저지시키기에는 무리가…","JPN":"そうするには怪我人が多過ぎます。今すぐ怪獣を阻止するには無理が……","ENG":"A lot of us are injured at the moment. We won't be enough to stop the monsters...","TWN":"但現在有很多傷者，要他們現在上場對付怪獸恐怕有些…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"경. 움직일 수 있는 병사를 모아라. 놈들이 마을에 가지 못하게 길목을 막는다.","JPN":"卿。動ける兵士を集めろ。奴らが村に近づけないよう、道を塞ぐ。","ENG":"Captain. Gather the soldiers who are able to fight. Stop the monsters from reaching the village.","TWN":"隊長，召集能行動的士兵，我們要堵住把路堵起來，不能讓怪獸們進到村裡。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L48_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"수를 줄이는 데만 전념하도록. 놓치는 녀석들까지 무리해서 추격할 필요는 없다.","JPN":"数を減らすことだけに専念しろ。逃した奴らまで無理に追いかける必要はない。","ENG":"Focus on diminishing their numbers. There is no need to exert yourself trying to chase them down.","TWN":"專注在減少它們的數量，不必勉強追擊逃走的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"전하. 아뢰옵기 황송하오나 저희는 몬테의 주민들을 지키기 위해 이곳에 온 것입니다.","JPN":"恐れながら、殿下。我々はモンテの住民を守るためにここへ来たのです。","ENG":"Your Highness, I have no intention of questioning your decision, but we are here to protect Monte and its villagers.","TWN":"殿下，冒昧進言，我們來此是為保護蒙特的居民。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"제 목숨을 보전하기 위해 싸움을 피할 생각은 없습니다!","JPN":"自分の命惜しさに、戦いを避けるつもりはありません！","ENG":"I will not avoid fighting to save my own life!","TWN":"我們不會為保全自己的性命而畏戰！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"경은 쓸데없는 고민을 하는군. 전하께서는 몬테의 주민들을 포기하신 게 아니야.","JPN":"卿は余計なことで悩むのだな。殿下はモンテの住民を放棄されたのではない。","ENG":"Cease with your silly concerns, Captain. His Highness did not give up on the villagers of Monte.","TWN":"隊長，你在擔心什麼？殿下並未放棄蒙特的居民。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"잊었나? 아직 마을에는 구원 기사단이 남아 있다는 걸.","JPN":"忘れたか？　まだ村には救世騎士団が残っているということを。","ENG":"Have you forgotten? The Knights of Redemption are in Monte.","TWN":"你忘記村莊裡還有救贖騎士團嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"네. 마을에는 루크레시아가 있으니 너무 걱정하실 필요 없어요.","JPN":"はい。村にはルクレシアがいますから、あまり心配しなくても大丈夫ですよ。","ENG":"That's right. Monte has Lucrecia, so there is no need to be so concerned.","TWN":"是的，村莊裡有露可蕾西亞，不用太擔心。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"저희는… 당장 저희가 할 수 있는 일을 하죠.","JPN":"僕たちは……僕たちにできることをしましょう。","ENG":"For now... we will do our part to help.","TWN":"我們…現在就做我們能做的事吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};